import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import './ArticleGrid.css';

// Paginated grid component with gold frames - 10 articles per page
const ArticleGrid = ({ articles }) => {
    const navigate = useNavigate();
    const [currentPage, setCurrentPage] = useState(1);
    const articlesPerPage = 10;

    const handleArticleClick = (id) => {
        navigate(`/article/${id}`);
    };

    // Calculate pagination
    const totalPages = Math.ceil(articles.length / articlesPerPage);
    const startIndex = (currentPage - 1) * articlesPerPage;
    const endIndex = startIndex + articlesPerPage;
    const currentArticles = articles.slice(startIndex, endIndex);

    const handlePageChange = (pageNumber) => {
        setCurrentPage(pageNumber);
        // Smooth scroll to top of the grid
        const gridSection = document.querySelector('.article-carousel-section');
        if (gridSection) {
            gridSection.scrollIntoView({ behavior: 'smooth', block: 'start' });
        }
    };

    const handlePrevPage = () => {
        if (currentPage > 1) {
            handlePageChange(currentPage - 1);
        }
    };

    const handleNextPage = () => {
        if (currentPage < totalPages) {
            handlePageChange(currentPage + 1);
        }
    };

    // Generate page numbers to display
    const getPageNumbers = () => {
        const pages = [];
        const maxPagesToShow = 5;

        if (totalPages <= maxPagesToShow) {
            for (let i = 1; i <= totalPages; i++) {
                pages.push(i);
            }
        } else {
            if (currentPage <= 3) {
                for (let i = 1; i <= maxPagesToShow; i++) {
                    pages.push(i);
                }
            } else if (currentPage >= totalPages - 2) {
                for (let i = totalPages - maxPagesToShow + 1; i <= totalPages; i++) {
                    pages.push(i);
                }
            } else {
                for (let i = currentPage - 2; i <= currentPage + 2; i++) {
                    pages.push(i);
                }
            }
        }
        return pages;
    };

    return (
        <div className="article-carousel-section">
            <div className="article-grid-wrapper">
                <div className="article-grid-container">
                    {currentArticles.map((article) => (
                        <div 
                            key={article.id} 
                            className="article-grid-item"
                            onClick={() => handleArticleClick(article.id)}
                        >
                            <div className="article-image-wrapper">
                                <img 
                                    src={article.image} 
                                    alt={article.title}
                                    className="article-grid-image"
                                    loading="lazy"
                                    draggable="false"
                                />
                                <div className="article-overlay">
                                    <div className="overlay-content">
                                        <h3 className="overlay-title">{article.title}</h3>
                                        <p className="overlay-category">{article.category}</p>
                                    </div>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>

                {/* Pagination Controls */}
                {totalPages > 1 && (
                    <div className="pagination-container">
                        <button 
                            className="pagination-btn pagination-prev"
                            onClick={handlePrevPage}
                            disabled={currentPage === 1}
                            aria-label="Previous page"
                        >
                            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                <path d="M15 19l-7-7 7-7"/>
                            </svg>
                        </button>

                        <div className="pagination-pages">
                            {getPageNumbers().map((pageNum) => (
                                <button
                                    key={pageNum}
                                    className={`pagination-page ${currentPage === pageNum ? 'active' : ''}`}
                                    onClick={() => handlePageChange(pageNum)}
                                >
                                    {pageNum}
                                </button>
                            ))}
                        </div>

                        <button 
                            className="pagination-btn pagination-next"
                            onClick={handleNextPage}
                            disabled={currentPage === totalPages}
                            aria-label="Next page"
                        >
                            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                <path d="M9 5l7 7-7 7"/>
                            </svg>
                        </button>
                    </div>
                )}

                {/* Articles counter */}
                <div className="articles-info">
                    Showing {startIndex + 1}–{Math.min(endIndex, articles.length)} of {articles.length} articles
                </div>
            </div>
        </div>
    );
};

export default ArticleGrid;
